const Redis = require('ioredis');
const redis = new Redis({ host: 'redis', port: 6379 });
const chatId = $input.first().json.chat_id;
const textoNuevo = $input.first().json.texto_completo;
const instance = $input.first().json.instance;

let history = [];
let state = {};
try {
  const h = await redis.get('tp:history:' + chatId);
  if (h) history = JSON.parse(h);
  const s = await redis.get('tp:state:' + chatId);
  if (s) state = JSON.parse(s);
} finally { await redis.quit(); }

// Agregar mensaje nuevo del cliente
history.push({ role: 'user', content: textoNuevo });

// Limitar historial a 20 mensajes
if (history.length > 20) history = history.slice(-20);

return [{ json: { chat_id: chatId, instance, history, state, texto_nuevo: textoNuevo } }];

const response = $input.first().json;
const rawText = response.content?.[0]?.text || '{}';
let parsed = {};
try {
  // Extraer JSON aunque venga con texto extra
  const match = rawText.match(/\{[\s\S]*\}/);
  parsed = match ? JSON.parse(match[0]) : { reply: rawText, action: 'none' };
} catch(e) {
  parsed = { reply: rawText, action: 'none' };
}
const prev = $('Cargar Historial').first().json;
return [{ json: {
  ...prev,
  reply: parsed.reply || '',
  action: parsed.action || 'none',
  check_date: parsed.check_date || '',
  appointment: parsed.appointment || {}
}}];

const events = $input.all().map(i => i.json);
const prev = $('Parsear Respuesta Claude').first().json;
const date = prev.check_date;
const duracion = prev.appointment?.duracion_min || 60;

// Horarios del día
const dia = new Date(date + 'T12:00:00-03:00').getDay(); // 0=dom, 6=sab
let franjas = [];
if (dia === 0) { // domingo
  franjas = [];
} else if (dia === 6) { // sabado
  franjas = [{start: '14:00', end: '18:00'}];
} else {
  franjas = [{start: '09:00', end: '12:00'}, {start: '14:00', end: '20:00'}];
}

// Turnos ocupados
const ocupados = events
  .filter(e => e.start?.dateTime)
  .map(e => ({
    inicio: new Date(e.start.dateTime),
    fin: new Date(e.end.dateTime)
  }));

// Generar slots de duracion minutos en cada franja
const slots = [];
for (const franja of franjas) {
  let cursor = new Date(date + 'T' + franja.start + ':00-03:00');
  const franjaFin = new Date(date + 'T' + franja.end + ':00-03:00');
  while (new Date(cursor.getTime() + duracion * 60000) <= franjaFin) {
    const slotFin = new Date(cursor.getTime() + duracion * 60000);
    const libre = !ocupados.some(o => cursor < o.fin && slotFin > o.inicio);
    if (libre) slots.push(cursor.toLocaleTimeString('es-AR', {hour:'2-digit', minute:'2-digit', timeZone:'America/Argentina/Buenos_Aires'}));
    cursor = new Date(cursor.getTime() + 30 * 60000); // avanzar 30 min
  }
}

const disponibilidad = slots.length > 0
  ? `Horarios disponibles para el ${date}: ${slots.slice(0,6).join(', ')}`
  : `No hay turnos disponibles para el ${date}.`;

return [{ json: { ...prev, disponibilidad } }];

